
package com.example.taxgap.service; import com.example.taxgap.domain.dto.report.*; import com.example.taxgap.repository.*; import org.springframework.stereotype.Service; import java.math.BigDecimal; import java.util.*;
@Service public class ReportService { private final FinancialTransactionRepository txnRepo; private final ExceptionRecordRepository excRepo; public ReportService(FinancialTransactionRepository t, ExceptionRecordRepository e){txnRepo=t;excRepo=e;} public List<CustomerTaxSummaryRow> customerSummary(){ List<Object[]> rows=txnRepo.aggregateCustomerSummary(); List<CustomerTaxSummaryRow> out=new ArrayList<>(); for(Object[] r: rows){ String customerId=(String)r[0]; BigDecimal totalAmount=toBD(r[1]); BigDecimal totalReportedTax=toBD(r[2]); BigDecimal totalExpectedTax=toBD(r[3]); BigDecimal totalTaxGap=toBD(r[4]); double score=r[5]==null?0.0:((Number)r[5]).doubleValue(); out.add(new CustomerTaxSummaryRow(customerId,totalAmount,totalReportedTax,totalExpectedTax,totalTaxGap,score)); } return out; } public ExceptionSummary exceptionSummary(){ long total=excRepo.total(); long high=excRepo.high(); long med=excRepo.medium(); long low=excRepo.low(); return new ExceptionSummary(total,high,med,low,null,0); } public List<ExceptionSummary> exceptionSummaryPerCustomer(){ List<ExceptionSummary> list=new ArrayList<>(); for(Object[] row: excRepo.perCustomer()){ list.add(new ExceptionSummary(0,0,0,0,(String)row[0], ((Number)row[1]).longValue())); } return list; } private BigDecimal toBD(Object o){ if(o==null) return BigDecimal.ZERO; if(o instanceof BigDecimal bd) return bd; return new BigDecimal(o.toString()); } }
